"use client";

import { useState } from "react";
import { movies } from "../data/movies";
import type { Movie } from "../data/movies";
import { X, User } from "lucide-react";

function getYouTubeEmbedUrl(url: string): string | null {
  const match = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&?]+)/);
  return match ? `https://www.youtube.com/embed/${match[1]}` : null;
}

function getXEmbedUrl(url: string): string {
  const match = url.match(/status\/(\d+)/);
  return match ? `https://embed.x.com/i/status/${match[1]}` : url;
}

export default function Home() {
  const [selected, setSelected] = useState<Movie | null>(null);

  return (
    <main className="min-h-screen bg-[#0d1117] p-4 sm:p-6">
      <p className="text-gray-400 mb-6 text-sm sm:text-base">
        クリックするとポップアップで動画が再生されます
      </p>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {movies.map((movie) => (
          <button
            key={movie.id}
            type="button"
            onClick={() => setSelected(movie)}
            className="group text-left rounded-lg border border-gray-700 bg-[#161b22] p-4 hover:border-blue-500/60 hover:bg-[#21262d] transition"
          >
            <div className="font-semibold text-white group-hover:text-blue-300 line-clamp-2">
              {movie.title}
            </div>
            <div className="flex items-center gap-1 mt-2 text-sm text-gray-400">
              <User className="w-4 h-4" />
              {movie.author}
            </div>
          </button>
        ))}
      </div>

      {selected && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 p-4"
          onClick={() => setSelected(null)}
        >
          <div
            className="relative w-full max-w-4xl rounded-lg overflow-hidden bg-[#161b22] shadow-xl"
            onClick={(e) => e.stopPropagation()}
          >
            <button
              type="button"
              className="absolute top-2 right-2 z-10 p-1 rounded-full bg-black/60 text-white hover:bg-black/80"
              onClick={() => setSelected(null)}
            >
              <X className="w-6 h-6" />
            </button>

            <div className="p-4">
              <h2 className="text-lg font-semibold text-white mb-1">
                {selected.title}
              </h2>
              <p className="text-sm text-gray-400 mb-4">{selected.author}</p>

              <div className="aspect-video bg-black rounded">
                {selected.source === "youtube" ? (
                  getYouTubeEmbedUrl(selected.url) ? (
                    <iframe
                      src={getYouTubeEmbedUrl(selected.url)!}
                      title={selected.title}
                      className="w-full h-full"
                      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                      allowFullScreen
                    />
                  ) : (
                    <a
                      href={selected.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center justify-center h-full text-blue-400 underline"
                    >
                      YouTubeで開く
                    </a>
                  )
                ) : (
                  <iframe
                    src={getXEmbedUrl(selected.url)}
                    title={selected.title}
                    className="w-full h-full min-h-[400px]"
                  />
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </main>
  );
}

